+      agents.push(agent);
+    }
+
+    // Benchmark coordination
+    const result = await benchmark(
+      async () => {
+        // Simulate coordination message broadcast
+        await Promise.all(
+          agents.map(agent => agent.execute('coordinate-task'))
+        );
+      },
+      {
+        iterations: 100,
+        warmup: 10,
+        name: `coordination-${count}-agents`,
+        silent: true,
