+/**
+ * Performance Benchmark Utility
+ * Provides accurate benchmarking with warmup, iterations, and statistical analysis
+ */
+
+export interface BenchmarkOptions {
+  iterations?: number;
+  warmup?: number;
+  name?: string;
+  silent?: boolean;
+  minSamples?: number;
+  maxTime?: number; // Maximum time in ms to run benchmark
+}
+
+export interface BenchmarkResult {
+  name: string;
+  iterations: number;
+  samples: number[];
+  mean: number;
+  median: number;
+  p50: number;
+  p75: number;
+  p90: number;
+  p95: number;
+  p99: number;
+  p999: number;
+  min: number;
+  max: number;
+  stdDev: number;
+  opsPerSecond: number;
+  totalTime: number;
+}
+
+export interface RegressionResult {
